mapper.select:
SELECT * FROM (
    SELECT INNER_Q.*, ROWNUM AS RN FROM (

        ORDER BY TO_DATE(REPLACE(AR.AR_DATE_STR, '/', '-'), 'YYYY-MM-DD') DESC,
                 AR.R_TIME DESC,
                 HE.DEPTNO,
                 HE.EMPID
    ) INNER_Q
    WHERE ROWNUM <= #{start, jdbcType=INTEGER} + #{length, jdbcType=INTEGER}
) WHERE RN > #{start, jdbcType=INTEGER}

mapper.update:
UPDATE AR_MAC_RECORDS_HTSV
   SET ACTIVITY = 0
 WHERE RECORD_NO = #{recordNo, jdbcType=NUMERIC}

mapper.select:
SELECT COUNT(*)
  FROM AR_MAC_RECORDS_HTSV
 WHERE CARD_NO   = #{cardNo,        jdbcType=VARCHAR}
   AND R_TIME    = TO_DATE(#{swipeDatetime, jdbcType=VARCHAR}, 'YYYY/MM/DD HH24:MI')
   AND DOOR_TYPE = #{doorType,      jdbcType=VARCHAR}
   AND ACTIVITY  = 1
